-int main(int argc, char** argv) {
-  // Sets up command line flag parsing, etc.
-  caffe2::GlobalInit(&argc, &argv);
-
-  if (c10::FLAGS_source_vocab_path.empty() ||
-      c10::FLAGS_target_vocab_path.empty() ||
-      c10::FLAGS_encoder_model.empty() ||
