-      c10::FLAGS_decoder_step_model,
-      c10::FLAGS_reverse_source,
-      c10::FLAGS_stop_at_eos,
-      c10::FLAGS_append_eos_to_source,
-      c10::FLAGS_length_penalty);
-
-  if (decoder == nullptr) {
-    LOG(FATAL) << "failed to load decoder";
-  }
-
-  LOG(INFO) << "Ready to translate";
